{"meta": null, "content": [{"type": "text", "text": "{"content":"1: #include \"source/common/network/tcp_listener_impl.h\"\n2: \n3: #include \"envoy/common/exception.h\"\n4: #include \"envoy/common/platform.h\"\n5: #include \"envoy/config/core/v3/base.pb.h\"\n6: #include \"envoy/network/exception.h\"\n7: \n8: #include \"source/common/common/assert.h\"\n9: #include \"source/common/common/empty_string.h\"\n10: #include \"source/common/common/fmt.h\"\n11: #include \"source/common/common/utility.h\"\n12: #include \"source/common/event/dispatcher_impl.h\"\n13: #include \"source/common/event/file_event_impl.h\"\n14: #include \"source/common/network/address_impl.h\"\n15: #include \"source/common/network/io_socket_handle_impl.h\"\n16: #include \"source/common/runtime/runtime_keys.h\"\n17: \n18: namespace Envoy {\n19: namespace Network {\n20: \n21: bool TcpListenerImpl::rejectCxOverGlobalLimit() const {\n22:   // Enforce the global connection limit if necessary, immediately closing the accepted connection.\n23:   if (ignore_global_conn_limit_) {\n24:     return false;\n25:   }\n26:   // TODO(nezdolik): deprecate `overload.global_downstream_max_connections` key once\n27:   // downstream connections monitor extension is stable.\n28:   if (track_global_cx_limit_in_overload_manager_) {\n29:     // Check if runtime flag `overload.global_downstream_max_connections` is configured\n30:     // simultaneously with downstream connections monitor in overload manager.\n31:     if (runtime_.threadsafeSnapshot()-\u003eget(Runtime::Keys::GlobalMaxCxRuntimeKey)) {\n32:       ENVOY_LOG_ONCE_MISC(\n33:           warn,\n34:           \"Global downstream connections limits is configured via deprecated runtime key {} and in \"\n35:           \"{}. Using overload manager config.\",\n36:           Runtime::Keys::GlobalMaxCxRuntimeKey,\n37:           Server::OverloadProactiveResources::get().GlobalDownstreamMaxConnections);\n38:     }\n39:     // Try to allocate resource within overload manager. We do it once here, instead of checking if\n40:     // it is possible to allocate resource in this method and then actually allocating it later in\n41:     // the code to avoid race conditions.\n42:     return !(overload_state_-\u003etryAllocateResource(\n43:         Server::OverloadProactiveResourceName::GlobalDownstreamMaxConnections, 1));\n44:   } else {\n45:     // If the connection limit is not set, don't limit the connections, but still track them.\n46:     // TODO(tonya11en): In integration tests, threadsafeSnapshot is necessary since the\n47:     // FakeUpstreams use a listener and do not run in a worker thread. In practice, this code path\n48:     // will always be run on a worker thread, but to prevent failed assertions in test environments,\n49:     // threadsafe snapshots must be used. This must be revisited.\n50:     const uint64_t global_cx_limit = runtime_.threadsafeSnapshot()-\u003egetInteger(\n51:         Runtime::Keys::GlobalMaxCxRuntimeKey, std::numeric_limits\u003cuint64_t\u003e::max());\n52:     return AcceptedSocketImpl::acceptedSocketCount() \u003e= global_cx_limit;\n53:   }\n54: }\n55: \n56: absl::Status TcpListenerImpl::onSocketEvent(short flags) {\n57:   ASSERT(bind_to_port_);\n58:   ASSERT(flags \u0026 (Event::FileReadyType::Read));\n59: \n60:   uint32_t connections_accepted_from_kernel_count = 0;\n61:   for (; connections_accepted_from_kernel_count \u003c max_connections_to_accept_per_socket_event_;\n62:        ++connections_accepted_from_kernel_count) {\n63:     if (!socket_-\u003eioHandle().isOpen()) {\n64:       PANIC(fmt::format(\"listener accept failure: {}\", errorDetails(errno)));\n65:     }\n66: \n67:     sockaddr_storage remote_addr;\n68:     socklen_t remote_addr_len = sizeof(remote_addr);\n69: \n70:     IoHandlePtr io_handle =\n71:         socket_-\u003eioHandle().accept(reinterpret_cast\u003csockaddr*\u003e(\u0026remote_addr), \u0026remote_addr_len);\n72:     if (io_handle == nullptr) {\n73:       break;\n74:     }\n75: \n76:     if (rejectCxOverGlobalLimit()) {\n77:       // The global connection limit has been reached.\n78:       io_handle-\u003eclose();\n79:       cb_.onReject(TcpListenerCallbacks::RejectCause::GlobalCxLimit);\n80:       continue;\n81:     } else if ((listener_accept_ != nullptr \u0026\u0026 listener_accept_-\u003eshouldShedLoad()) ||\n82:                random_.bernoulli(reject_fraction_)) {\n83:       io_handle-\u003eclose();\n84:       cb_.onReject(TcpListenerCallbacks::RejectCause::OverloadAction);\n85:       continue;\n86:     }\n87: \n88:     // Get the local address from the new socket if the listener is listening on IP ANY\n89:     // (e.g., 0.0.0.0 for IPv4) (local_address_ is nullptr in this case).\n90:     Address::InstanceConstSharedPtr local_address = local_address_;\n91:     if (!local_address) {\n92:       auto address_or_error = io_handle-\u003elocalAddress();\n93:       RETURN_IF_NOT_OK_REF(address_or_error.status());\n94:       local_address = std::move(address_or_error.value());\n95:     }\n96: \n97:     // The accept() call that filled in remote_addr doesn't fill in more than the sa_family field\n98:     // for Unix domain sockets; apparently there isn't a mechanism in the kernel to get the\n99:     // `sockaddr_un` associated with the client socket when starting from the server socket.\n100:     // We work around this by using our own name for the socket in this case.\n101:     // Pass the 'v6only' parameter as true if the local_address is an IPv6 address. This has no\n102:     // effect if the socket is a v4 socket, but for v6 sockets this will create an IPv4 remote\n103:     // address if an IPv4 local_address was created from an IPv6 mapped IPv4 address.\n104: \n105:     Address::InstanceConstSharedPtr remote_address;\n106:     if (remote_addr.ss_family == AF_UNIX) {\n107:       auto address_or_error = io_handle-\u003epeerAddress();\n108:       RETURN_IF_NOT_OK_REF(address_or_error.status());\n109:       remote_address = std::move(address_or_error.value());\n110:     } else {\n111:       auto address_or_error = Address::addressFromSockAddr(\n112:           remote_addr, remote_addr_len, local_address-\u003eip()-\u003eversion() == Address::IpVersion::v6);\n113:       RETURN_IF_NOT_OK_REF(address_or_error.status());\n114:       remote_address = std::move(address_or_error.value());\n115:     }\n116: \n117:     cb_.onAccept(std::make_unique\u003cAcceptedSocketImpl\u003e(std::move(io_handle), local_address,\n118:                                                       remote_address, overload_state_,\n119:                                                       track_global_cx_limit_in_overload_manager_));\n120:   }\n121: \n122:   ENVOY_LOG_MISC(trace, \"TcpListener accepted {} new connections.\",\n123:                  connections_accepted_from_kernel_count);\n124:   cb_.recordConnectionsAcceptedOnSocketEvent(connections_accepted_from_kernel_count);\n125:   return absl::OkStatus();\n126: }\n127: \n128: TcpListenerImpl::TcpListenerImpl(Event::Dispatcher\u0026 dispatcher, Random::RandomGenerator\u0026 random,\n129:                                  Runtime::Loader\u0026 runtime, SocketSharedPtr socket,\n130:                                  TcpListenerCallbacks\u0026 cb, bool bind_to_port,\n131:                                  bool ignore_global_conn_limit, bool bypass_overload_manager,\n132:                                  uint32_t max_connections_to_accept_per_socket_event,\n133:                                  Server::ThreadLocalOverloadStateOptRef overload_state)\n134:     : BaseListenerImpl(dispatcher, std::move(socket)), cb_(cb), random_(random), runtime_(runtime),\n135:       bind_to_port_(bind_to_port), reject_fraction_(0.0),\n136:       ignore_global_conn_limit_(ignore_global_conn_limit),\n137:       bypass_overload_manager_(bypass_overload_manager),\n138:       max_connections_to_accept_per_socket_event_(max_connections_to_accept_per_socket_event),\n139:       overload_state_(overload_state),\n140:       track_global_cx_limit_in_overload_manager_(\n141:           overload_state_\n142:               ? overload_state_-\u003eisResourceMonitorEnabled(\n143:                     Server::OverloadProactiveResourceName::GlobalDownstreamMaxConnections)\n144:               : false) {\n145:   if (bind_to_port) {\n146:     // Use level triggered mode to avoid potential loss of the trigger due to\n147:     // transient accept errors or early termination due to accepting\n148:     // max_connections_to_accept_per_socket_event connections.\n149:     socket_-\u003eioHandle().initializeFileEvent(\n150:         dispatcher, [this](uint32_t events) { return onSocketEvent(events); },\n151:         Event::FileTriggerType::Level, Event::FileReadyType::Read);\n152:   }\n153: }\n154: \n155: void TcpListenerImpl::enable() {\n156:   if (bind_to_port_) {\n157:     socket_-\u003eioHandle().enableFileEvents(Event::FileReadyType::Read);\n158:   } else {\n159:     ENVOY_LOG_MISC(debug, \"The listener cannot be enabled since it's not bind to port.\");\n160:   }\n161: }\n162: \n163: void TcpListenerImpl::disable() {\n164:   if (bind_to_port_) {\n165:     socket_-\u003eioHandle().enableFileEvents(0);\n166:   } else {\n167:     ENVOY_LOG_MISC(debug, \"The listener cannot be disable since it's not bind to port.\");\n168:   }\n169: }\n170: \n171: void TcpListenerImpl::setRejectFraction(const UnitFloat reject_fraction) {\n172:   reject_fraction_ = reject_fraction;\n173: }\n174: \n175: void TcpListenerImpl::configureLoadShedPoints(\n176:     Server::LoadShedPointProvider\u0026 load_shed_point_provider) {\n177:   listener_accept_ =\n178:       load_shed_point_provider.getLoadShedPoint(Server::LoadShedPointName::get().TcpListenerAccept);\n179:   ENVOY_LOG_ONCE_MISC_IF(\n180:       trace, listener_accept_ == nullptr,\n181:       \"LoadShedPoint envoy.load_shed_points.tcp_listener_accept is not found. Is it configured?\");\n182: }\n183: \n184: bool TcpListenerImpl::shouldBypassOverloadManager() const { return by