{"meta": null, "content": [{"type": "text", "text": "{"content":"1: #include \"source/common/listener_manager/active_tcp_listener.h\"\n2: \n3: #include \u003cchrono\u003e\n4: \n5: #include \"envoy/event/dispatcher.h\"\n6: #include \"envoy/stats/scope.h\"\n7: \n8: #include \"source/common/common/assert.h\"\n9: #include \"source/common/network/connection_impl.h\"\n10: #include \"source/common/network/utility.h\"\n11: \n12: namespace Envoy {\n13: namespace Server {\n14: \n15: ActiveTcpListener::ActiveTcpListener(Network::TcpConnectionHandler\u0026 parent,\n16:                                      Network::ListenerConfig\u0026 config, Runtime::Loader\u0026 runtime,\n17:                                      Random::RandomGenerator\u0026 random,\n18:                                      Network::SocketSharedPtr\u0026\u0026 socket,\n19:                                      Network::Address::InstanceConstSharedPtr\u0026 listen_address,\n20:                                      Network::ConnectionBalancer\u0026 connection_balancer,\n21:                                      ThreadLocalOverloadStateOptRef overload_state)\n22:     : OwnedActiveStreamListenerBase(\n23:           parent, parent.dispatcher(),\n24:           parent.createListener(std::move(socket), *this, runtime, random, config, overload_state),\n25:           config),\n26:       tcp_conn_handler_(parent), connection_balancer_(connection_balancer),\n27:       listen_address_(listen_address) {\n28:   connection_balancer_.registerHandler(*this);\n29: }\n30: \n31: ActiveTcpListener::ActiveTcpListener(Network::TcpConnectionHandler\u0026 parent,\n32:                                      Network::ListenerPtr\u0026\u0026 listener,\n33:                                      Network::Address::InstanceConstSharedPtr\u0026 listen_address,\n34:                                      Network::ListenerConfig\u0026 config,\n35:                                      Network::ConnectionBalancer\u0026 connection_balancer,\n36:                                      Runtime::Loader\u0026)\n37:     : OwnedActiveStreamListenerBase(parent, parent.dispatcher(), std::move(listener), config),\n38:       tcp_conn_handler_(parent), connection_balancer_(connection_balancer),\n39:       listen_address_(listen_address) {\n40:   connection_balancer_.registerHandler(*this);\n41: }\n42: \n43: ActiveTcpListener::~ActiveTcpListener() {\n44:   is_deleting_ = true;\n45:   connection_balancer_.unregisterHandler(*this);\n46: \n47:   // Purge sockets that have not progressed to connections. This should only happen when\n48:   // a listener filter stops iteration and never resumes.\n49:   while (!sockets_.empty()) {\n50:     auto removed = sockets_.front()-\u003eremoveFromList(sockets_);\n51:     dispatcher().deferredDelete(std::move(removed));\n52:   }\n53: \n54:   for (auto\u0026 [chain, active_connections] : connections_by_context_) {\n55:     ASSERT(active_connections != nullptr);\n56:     auto\u0026 connections = active_connections-\u003econnections_;\n57:     while (!connections.empty()) {\n58:       connections.front()-\u003econnection_-\u003eclose(\n59:           Network::ConnectionCloseType::NoFlush,\n60:           \"purging_socket_that_have_not_progressed_to_connections\");\n61:     }\n62:   }\n63:   dispatcher().clearDeferredDeleteList();\n64: \n65:   // By the time a listener is destroyed, in the common case, there should be no connections.\n66:   // However, this is not always true if there is an in flight rebalanced connection that is\n67:   // being posted. This assert is extremely useful for debugging the common path so we will leave it\n68:   // for now. If it becomes a problem (developers hitting this assert when using debug builds) we\n69:   // can revisit. This case, if it happens, should be benign on production builds. This case is\n70:   // covered in ConnectionHandlerTest::RemoveListenerDuringRebalance.\n71:   ASSERT(num_listener_connections_ == 0, fmt::format(\"destroyed listener {} has {} connect