135: void OwnedActiveStreamListenerBase::removeConnection(ActiveTcpConnection& connection) {
136:   ENVOY_CONN_LOG(debug, "adding to cleanup list", *connection.connection_);
137:   ActiveConnections& active_connections = connection.active_connections_;
138:   ActiveConnectionPtr removed = connection.removeFromList(active_connections.connections_);
139:   dispatcher().deferredDelete(std::move(removed));
140:   // Delete map entry if and only if connections_ becomes empty.
141:   if (active_connections.connections_.empty()) {
142:     auto iter = connections_by_context_.find(&active_connections.filter_chain_);
143:     ASSERT(iter != connections_by_context_.end());
144:     // To cover the lifetime of every single connection, Connections need to be deferred deleted
145:     // because the previously contained connection is deferred deleted.
146:     dispatcher().deferredDelete(std::move(iter->second));
147:     // The erase will break the iteration over the connections_by_context_ during the deletion.
148:     if (!is_deleting_) {
149:       connections_by_context_.erase(iter);
150:     }
151:   }
152: }
