154: ActiveConnections& OwnedActiveStreamListenerBase::getOrCreateActiveConnections(
155:     const Network::FilterChain& filter_chain) {
156:   ActiveConnectionCollectionPtr& connections = connections_by_context_[&filter_chain];
157:   if (connections == nullptr) {
158:     connections = std::make_unique<ActiveConnections>(*this, filter_chain);
159:   }
160:   return *connections;
161: }
162: 
163: void OwnedActiveStreamListenerBase::removeFilterChain(const Network::FilterChain* filter_chain) {
164:   auto iter = connections_by_context_.find(filter_chain);
165:   if (iter == connections_by_context_.end()) {
166:     // It is possible when listener is stopping.
167:   } else {
168:     auto& connections = iter->second->connections_;
169:     while (!connections.empty()) {
170:       connections.front()->connection_->close(Network::ConnectionCloseType::NoFlush,
171:                                               "filter_chain_is_being_removed");
172:     }
173:     // Since is_deleting_ is on, we need to manually remove the map value and drive the
174:     // iterator. Defer delete connection container to avoid race condition in destroying
175:     // connection.
176:     dispatcher().deferredDelete(std::move(iter->second));
177:     connections_by_context_.erase(iter);
178:   }
179: }
