{"meta": null, "content": [{"type": "text", "text": "{"content":"510: \n511: }; // namespace\n512: \n513: const Network::FilterChain*\n514: FilterChainManagerImpl::findFilterChain(const Network::ConnectionSocket\u0026 socket,\n515:                                         const StreamInfo::StreamInfo\u0026 info) const {\n516:   if (matcher_) {\n517:     return findFilterChainUsingMatcher(socket, info);\n518:   }\n519: \n520:   const auto\u0026 address = socket.connectionInfoProvider().localAddress();\n521: \n522:   const Network::FilterChain* best_match_filter_chain = nullptr;\n523:   // Match on destination port (only for IP addresses).\n524:   if (address-\u003etype() == Network::Address::Type::Ip) {\n525:     const auto port_match = destination_ports_map_.find(address-\u003eip()-\u003eport());\n526:     if (port_match != destination_ports_map_.end()) {\n527:       best_match_filter_chain = findFilterChainForDestinationIP(*port_match-\u003esecond.second, socket);\n528:       if (best_match_filter_chain != nullptr) {\n529:         return best_match_filter_chain;\n530:       } else {\n531:         // There is entry for specific port but none of the filter chain matches. Instead of\n532:         // matching catch-all port 0, the fallback filter chain is returned.\n533:         return default_filter_chain_.get();\n534:       }\n535:     }\n536:   }\n537:   // Match on catch-all port 0 if there is no specific port sub tree.\n538:   const auto port_match = destination_ports_map_.find(0);\n539:   if (port_match != destination_ports_map_.end()) {\n540:     best_match_filter_chain = findFilterChainForDestinationIP(*port_match-\u003esecond.second, socket);\n541:   }\n542:   return best_match_filter_chain != nullptr\n543:              ? best_match_filter_chain\n544:              // Neither exact port nor catch-all port matches. Use fallback filter chain.\n545:              : default_filter_chain_.get();\n546: }\n547: \n548: const Network::FilterChain*\n549: FilterChainManagerImpl::findFilterChainUsingMatcher(const Network::ConnectionSocket\u0026 socket,\n550:                                                     const StreamInfo::StreamInfo\u0026 info) const {\n551:   Network::Matching::MatchingDataImpl data(socket, info.filterState(), info.dynamicMetadata());\n552:   const auto\u0026 match_result = Matcher::evaluateMatch\u003cNetwork::MatchingData\u003e(*matcher_, data);\n553:   ASSERT(match_result.match_state_ == Matcher::MatchState::MatchComplete,\n554:          \"Matching must complete for network streams.\");\n555:   if (match_result.result_) {\n556:     const auto result = match_result.result_();\n557:     return result-\u003egetTyped\u003cConfiguration::FilterChainBaseAction\u003e().get(filter_chains_by_name_,\n558:                                                                         info);\n559:   }\n560:   return default_filter_chain_.get();\n561: }\n562: \n563: const Network::FilterChain* FilterChainManagerImpl::findFilterChainForDestinationIP(\n564:     const DestinationIPsTrie\u0026 destination_ips_trie, const Network::ConnectionSocket\u0026 socket) const {\n565:   auto address = socket.connectionInfoProvider().localAddress();\n566:   if (address-\u003etype() != Network::Address::Type::Ip) {\n567:     address = FilterChain::fakeAddress();\n568:   }\n569: \n570:   // Match on both: exact IP and wider CIDR ranges using LcTrie.\n571:   const auto\u0026 data = destination_ips_trie.getData(address);\n572:   if (!data.empty()) {\n573:     ASSERT(data.size() == 1);\n574:     return findFilterChainForServerName(*data.back(), socket);\n575:   }\n576: \n577:   return nullptr;\n578: }\n579: \n580: const Network::FilterChain* FilterChainManagerImpl::findFilterChainForServerName(\n581: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/envoy--d7809ba2@449050ec9ea290303692f0ec2b09fceb31308b9a/-/blob/source/common/listener_manager/filter_chain_manager_impl.cc%3FL510-580"}", "annotations": null, "meta": null}], "structuredContent": {"content": "510: 
