558: void ConnectionManagerImpl::resetAllStreams(
559:     absl::optional<StreamInfo::CoreResponseFlag> response_flag, absl::string_view details) {
560:   while (!streams_.empty()) {
561:     // Mimic a downstream reset in this case. We must also remove callbacks here. Though we are
562:     // about to close the connection and will disable further reads, it is possible that flushing
563:     // data out can cause stream callbacks to fire (e.g., low watermark callbacks).
564:     //
565:     // TODO(mattklein123): I tried to actually reset through the codec here, but ran into issues
566:     // with nghttp2 state and being unhappy about sending reset frames after the connection had
567:     // been terminated via GOAWAY. It might be possible to do something better here inside the h2
568:     // codec but there are no easy answers and this seems simpler.
569:     auto& stream = *streams_.front();
570:     stream.response_encoder_->getStream().removeCallbacks(stream);
571:     if (!stream.response_encoder_->getStream().responseDetails().empty()) {
572:       stream.filter_manager_.streamInfo().setResponseCodeDetails(
573:           stream.response_encoder_->getStream().responseDetails());
574:     } else if (!details.empty()) {
575:       stream.filter_manager_.streamInfo().setResponseCodeDetails(details);
576:     }
577:     if (response_flag.has_value()) {
578:       stream.filter_manager_.streamInfo().setResponseFlag(response_flag.value());
579:     }
580:     stream.onResetStream(StreamResetReason::ConnectionTermination, absl::string_view());
581:   }
582: }
