227: void ConnectionManagerImpl::checkForDeferredClose(bool skip_delay_close) {
228:   Network::ConnectionCloseType close = Network::ConnectionCloseType::FlushWriteAndDelay;
229:   if (runtime_.snapshot().getBoolean(ConnectionManagerImpl::OptionallyDelayClose, true) &&
230:       skip_delay_close) {
231:     close = Network::ConnectionCloseType::FlushWrite;
232:   }
233:   if (drain_state_ == DrainState::Closing && streams_.empty() && !codec_->wantsToWrite()) {
234:     // We are closing a draining connection with no active streams and the codec has
235:     // nothing to write.
236:     doConnectionClose(close, absl::nullopt,
237:                       StreamInfo::LocalCloseReasons::get().DeferredCloseOnDrainedConnection);
238:   }
239: }
