241: void ConnectionManagerImpl::doEndStream(ActiveStream& stream, bool check_for_deferred_close) {
242:   // The order of what happens in this routine is important and a little complicated. We first see
243:   // if the stream needs to be reset. If it needs to be, this will end up invoking reset callbacks
244:   // and then moving the stream to the deferred destruction list. If the stream has not been reset,
245:   // we move it to the deferred deletion list here. Then, we potentially close the connection. This
246:   // must be done after deleting the stream since the stream refers to the connection and must be
247:   // deleted first.
248:   bool reset_stream = false;
249:   // If the response encoder is still associated with the stream, reset the stream. The exception
250:   // here is when Envoy "ends" the stream by calling recreateStream at which point recreateStream
251:   // explicitly nulls out response_encoder to avoid the downstream being notified of the
252:   // Envoy-internal stream instance being ended.
253:   if (stream.response_encoder_ != nullptr &&
254:       (!stream.filter_manager_.hasLastDownstreamByteReceived() ||
255:        !stream.state_.codec_saw_local_complete_)) {
256:     // Indicate local is complete at this point so that if we reset during a continuation, we don't
257:     // raise further data or trailers.
258:     ENVOY_STREAM_LOG(debug, "doEndStream() resetting stream", stream);
259:     // TODO(snowp): This call might not be necessary, try to clean up + remove setter function.
260:     stream.filter_manager_.setLocalComplete();
261:     stream.state_.codec_saw_local_complete_ = true;
262: 
263:     // Per https://tools.ietf.org/html/rfc7540#section-8.3 if there was an error
264:     // with the TCP connection during a CONNECT request, it should be
265:     // communicated via CONNECT_ERROR
266:     if (requestWasConnect(stream.request_headers_, codec_->protocol()) &&
267:         (stream.filter_manager_.streamInfo().hasResponseFlag(
268:              StreamInfo::CoreResponseFlag::UpstreamConnectionFailure) ||
269:          stream.filter_manager_.streamInfo().hasResponseFlag(
270:              StreamInfo::CoreResponseFlag::UpstreamConnectionTermination))) {
271:       stream.response_encoder_->getStream().resetStream(StreamResetReason::ConnectError);
272:     } else {
273:       if (stream.filter_manager_.streamInfo().hasResponseFlag(
274:               StreamInfo::CoreResponseFlag::UpstreamProtocolError)) {
275:         stream.response_encoder_->getStream().resetStream(StreamResetReason::ProtocolError);
276:       } else {
277:         stream.response_encoder_->getStream().resetStream(StreamResetReason::LocalReset);
278:       }
279:     }
280:     reset_stream = true;
281:   }
282: 
283:   if (!reset_stream) {
284:     doDeferredStreamDestroy(stream);
285:   }
286: 
287:   if (reset_stream && codec_->protocol() < Protocol::Http2) {
288:     drain_state_ = DrainState::Closing;
289:   }
290: 
291:   if (check_for_deferred_close) {
292:     // If HTTP/1.0 has no content length, it is framed by close and won't consider
293:     // the request complete until the FIN is read. Don't delay close in this case.
294:     const bool http_10_sans_cl =
295:         (codec_->protocol() == Protocol::Http10) &&
296:         (!stream.response_headers_ || !stream.response_headers_->ContentLength());
297:     // We also don't delay-close in the case of HTTP/1.1 where the request is
298:     // fully read, as there's no race condition to avoid.
299:     const bool connection_close =
300:         stream.filter_manager_.streamInfo().shouldDrainConnectionUponCompletion();
301:     const bool request_complete = stream.filter_manager_.hasLastDownstreamByteReceived();
302: 
303:     // Don't do delay close for HTTP/1.0 or if the request is complete.
304:     checkForDeferredClose(connection_close && (request_complete || http_10_sans_cl));
305:   }
306: }
