421:     stats_.named_.downstream_cx_max_requests_reached_.inc();
422:   }
423: 
424:   if (soft_drain_http1_) {
425:     new_stream->filter_manager_.streamInfo().setShouldDrainConnectionUponCompletion(true);
426:     // Prevent erroneous debug log of closing due to incoming connection close header.
427:     drain_state_ = DrainState::Closing;
428:   }
429: 
430:   new_stream->state_.is_internally_created_ = is_internally_created;
431:   new_stream->response_encoder_ = &response_encoder;
432:   new_stream->response_encoder_->getStream().addCallbacks(*new_stream);
433:   new_stream->response_encoder_->getStream().registerCodecEventCallbacks(new_stream.get());
434:   new_stream->response_encoder_->getStream().setFlushTimeout(new_stream->idle_timeout_ms_);
435:   new_stream->streamInfo().setDownstreamBytesMeter(response_encoder.getStream().bytesMeter());
436:   // If the network connection is backed up, the stream should be made aware of it on creation.
437:   // Both HTTP/1.x and HTTP/2 codecs handle this in StreamCallbackHelper::addCallbacksHelper.
438:   ASSERT(read_callbacks_->connection().aboveHighWatermark() == false ||
