461:   // If Envoy is not configured to proxy 100-Continue responses, swallow the 100 Continue
462:   // here. This avoids the potential situation where Envoy strips Expect: 100-Continue and sends a
463:   // 100-Continue, then proxies a duplicate 100 Continue from upstream.
464:   if (parent_.proxy_100_continue_) {
465:     parent_.filter_manager_callbacks_.setInformationalHeaders(std::move(headers));
466:     parent_.encode1xxHeaders(nullptr, *parent_.filter_manager_callbacks_.informationalHeaders());
467:   }
468: }
