470: void ActiveStreamDecoderFilter::stopDecodingIfNonTerminalFilterEncodedEndStream(
471:     bool encoded_end_stream) {
472:   // Encoding end_stream by a non-terminal filters (i.e. cache filter) always causes the decoding to
473:   // be stopped even if independent half-close is enabled. For simplicity, independent half-close is
474:   // allowed only when the terminal (router) filter is encoding the response.
475:   if (encoded_end_stream && !parent_.isTerminalDecoderFilter(*this) &&
476:       !parent_.state_.decoder_filter_chain_complete_) {
477:     parent_.state_.decoder_filter_chain_aborted_ = true;
478:   }
479: }
