589:     if (stopDecoderFilterChain() && std::next(entry) != decoder_filters_.end()) {
590:       maybeContinueDecoding(continue_data_entry);
591:       return;
592:     }
593: 
594:     const bool new_metadata_added = processNewlyAddedMetadata();
595:     // If end_stream is set in headers, and a filter adds new metadata, we need to delay end_stream
596:     // in headers by inserting an empty data frame with end_stream set. The empty data frame is sent
597:     // after the new metadata.
598:     if ((*entry)->end_stream_ && new_metadata_added && !buffered_request_data_) {
599:       Buffer::OwnedImpl empty_data("");
600:       ENVOY_STREAM_LOG(
601:           trace, "inserting an empty data frame for end_stream due metadata being added.", *this);
602:       // Metadata frame doesn't carry end of stream bit. We need an empty data frame to end the
603:       // stream.
604:       addDecodedData(*(*entry), empty_data, true);
605:     }
606: 
607:     if (!continue_iteration && std::next(entry) != decoder_filters_.end()) {
608:       // Stop iteration IFF this is not the last filter. If it is the last filter, continue with
609:       // processing since we need to handle the case where a terminal filter wants to buffer, but
610:       // a previous filter has added body.
611:       maybeContinueDecoding(continue_data_entry);
612:       return;
613:     }
614: 
615:     // Here we handle the case where we have a header only request, but a filter adds a body
616:     // to it. We need to not raise end_stream = true to further filters during inline iteration.
617:     if (end_stream && buffered_request_data_ && continue_data_entry == decoder_filters_.end()) {
618:       continue_data_entry = entry;
619:     }
620:     // The decoder filter chain is finished here if the following is true:
621:     // 1. the last filter has observed the end_stream AND
622:     // 2. no filter, including the last filter, has injected body during header iteration.
623:     // If body was injected the end_stream will be processed in the `decodeData()` method below.
624:     const bool no_body_was_injected = continue_data_entry == decoder_filters_.end();
625:     terminal_filter_decoded_end_stream =
626:         (std::next(entry) == decoder_filters_.end() && (*entry)->end_stream_) &&
627:         no_body_was_injected;
628:   }
629: 
630:   maybeContinueDecoding(continue_data_entry);
631: 
632:   if (end_stream) {
633:     disarmRequestTimeout();
634:   }
635:   maybeEndDecode(terminal_filter_decoded_end_stream);
636: }
