455: void UpstreamRequest::onResetStream(Http::StreamResetReason reason,
456:                                     absl::string_view transport_failure_reason) {
457:   ScopeTrackerScopeState scope(&parent_.callbacks()->scope(), parent_.callbacks()->dispatcher());
458: 
459:   if (span_ != nullptr) {
460:     // Add tags about reset.
461:     span_->setTag(Tracing::Tags::get().Error, Tracing::Tags::get().True);
462:     span_->setTag(Tracing::Tags::get().ErrorReason, Http::Utility::resetReasonToString(reason));
463:   }
464:   clearRequestEncoder();
465:   awaiting_headers_ = false;
466: 
467:   stream_info_.setResponseFlag(Filter::streamResetReasonToResponseFlag(reason));
468:   parent_.onUpstreamReset(reason, transport_failure_reason, *this);
469: }
