146: // This is the response headers arriving from the codec. Send them through the filter manager.
147: void UpstreamCodecFilter::CodecBridge::decodeHeaders(Http::ResponseHeaderMapPtr&& headers,
148:                                                      bool end_stream) {
149:   // TODO(rodaine): This is actually measuring after the headers are parsed and not the first
150:   // byte.
151:   filter_.upstreamTiming().onFirstUpstreamRxByteReceived(
152:       filter_.callbacks_->dispatcher().timeSource());
153: 
154:   if (filter_.callbacks_->upstreamCallbacks()->pausedForConnect() &&
155:       ((Http::CodeUtility::is2xx(Http::Utility::getResponseStatus(*headers))))) {
156:     filter_.callbacks_->upstreamCallbacks()->setPausedForConnect(false);
157:     filter_.callbacks_->continueDecoding();
158:   }
159: 
160:   if (filter_.callbacks_->upstreamCallbacks()->pausedForWebsocketUpgrade()) {
161:     const uint64_t status = Http::Utility::getResponseStatus(*headers);
162:     const auto protocol = filter_.callbacks_->upstreamCallbacks()->upstreamStreamInfo().protocol();
163:     if (status == static_cast<uint64_t>(Http::Code::SwitchingProtocols) ||
164:         (protocol.has_value() && protocol.value() != Envoy::Http::Protocol::Http11)) {
165:       // handshake is finished and continue the data processing.
166:       filter_.callbacks_->upstreamCallbacks()->setPausedForWebsocketUpgrade(false);
167:       filter_.callbacks_->continueDecoding();
168:     } else {
169:       // Other status, e.g., 426 or 200, indicate a failed handshake, Envoy as a proxy will proxy
170:       // back the response header to downstream and then close the request, since WebSocket
171:       // just needs headers for handshake per RFC-6455. Note: HTTP/2 200 will be normalized to
172:       // 101 before this point in codec and this patch will skip this scenario from the above
173:       // proto check.
174:       filter_.callbacks_->sendLocalReply(
175:           static_cast<Envoy::Http::Code>(status), "",
176:           [&headers](Http::ResponseHeaderMap& local_headers) {
177:             headers->iterate([&local_headers](const Envoy::Http::HeaderEntry& header) {
178:               local_headers.addCopy(Http::LowerCaseString(header.key().getStringView()),
179:                                     header.value().getStringView());
180:               return Envoy::Http::HeaderMap::Iterate::Continue;
181:             });
182:           },
183:           std::nullopt, StreamInfo::ResponseCodeDetails::get().WebsocketHandshakeUnsuccessful);
184:       return;
185:     }
186:   }
187: 
188:   maybeEndDecode(end_stream);
189:   filter_.callbacks_->encodeHeaders(std::move(headers), end_stream,
190:                                     StreamInfo::ResponseCodeDetails::get().ViaUpstream);
191: }
