221: void UpstreamCodecFilter::CodecBridge::onResetStream(Http::StreamResetReason reason,
222:                                                      absl::string_view transport_failure_reason) {
223:   if (filter_.calling_encode_headers_) {
224:     // If called while still encoding errors, the reset reason won't be appended to the details
225:     // string through the reset stream call, so append it here.
226:     std::string failure_reason(Http::Utility::resetReasonToString(reason));
227:     if (!transport_failure_reason.empty()) {
228:       absl::StrAppend(&failure_reason, "|", transport_failure_reason);
229:     }
230:     filter_.deferred_reset_status_ = absl::InternalError(failure_reason);
231:     return;
232:   }
233: 
234:   std::string failure_reason(transport_failure_reason);
235:   if (reason == Http::StreamResetReason::LocalReset) {
236:     if (!Runtime::runtimeFeatureEnabled(
237:             "envoy.reloadable_features.report_stream_reset_error_code")) {
238:       ASSERT(transport_failure_reason.empty());
239:       // Use this to communicate to the upstream request to not force-terminate.
240:       failure_reason = "codec_error";
241:     } else {
242:       failure_reason = absl::StrCat(transport_failure_reason, "|codec_error");
243:     }
244:   }
245:   filter_.callbacks_->resetStream(reason, failure_reason);
246: }
