tely as data is read from the connection.\n49:   for (auto\u0026 entry : upstream_filters_) {\n50:     if (entry-\u003efilter_ \u0026\u0026 !entry-\u003einitialized_) {\n51:       entry-\u003einitialized_ = true;\n52:       FilterStatus status = entry-\u003efilter_-\u003eonNewConnection();\n53:       if (status == FilterStatus::StopIteration || connection_.state() != Connection::State::Open) {\n54:         break;\n55:       }\n56:     }\n57:   }\n58: \n59:   return true;\n60: }\n61: \n62: void FilterManagerImpl::onContinueReading(ActiveReadFilter* filter,\n63:                                           ReadBufferSource\u0026 buffer_source) {\n64:   // Filter could return status == FilterStatus::StopIteration immediately, close the connection and\n65:   // use callback to call this function.\n66:   if (connection_.state() != Connection::State::Open) {\n67:     return;\n68:   }\n69: \n70:   std::list\u003cActiveReadFilterPtr\u003e::iterator entry;\n71:   if (!filter) {\n72:     connection_.streamInfo().addBytesReceived(buffer_source.getReadBuffer().buffer.length());\n73:     entry = upstream_filters_.begin();\n74:   } else {\n75:     entry = std::next(filter-\u003eentry());\n76:   }\n77: \n78:   for (; entry != upstream_filters_.end(); entry++) {\n79:     if (!(*entry)-\u003efilter_) {\n80:       continue;\n81:     }\n82:     if (!(*entry)-\u003einitialized_) {\n83:       (*entry)-\u003einitialized_ = true;\n84:       FilterStatus status = (*entry)-\u003efilter_-\u003eonNewConnection();\n85:       if (status == FilterStatus::StopIteration || connection_.state() != Connection::State::Open) {\n86:         return;\n87:       }\n88:     }\n89: \n90:     StreamBuffer read_buffer = buffer_source.getReadBuffer();\n91:     if (read_buffer.buffer.length() \u003e 0 || read_buffer.end_stream) {\n92:       FilterStatus status = (*entry)-\u003efilter_-\u003eonData(read_buffer.buffer, read_buffer.end_stream);\n93:       if (status == FilterStatus::StopIteration || connection_.state(