lClose(),\n145:                  close_action.closeSocket());\n146: \n147:   ENVOY_CONN_LOG(trace,\n148:                  \"maybeClose(): remote_close_pending_={}, local_close_pending_={}, \"\n149:                  \"filter_pending_close_count_={}\",\n150:                  connection_, state_.remote_close_pending_, state_.local_close_pending_,\n151:                  state_.filter_pending_close_count_);\n152: \n153:   if (latched_close_action_.has_value() \u0026\u0026 latched_close_action_-\u003ecloseSocket()) {\n154:     if (latched_close_action_-\u003eisLocalClose() || !close_action.closeSocket()) {\n155:       // If the previous close event is a local close and will close the socket, which will only\n156:       // happen when half close is enabled, or if the current close action does not close the\n157:       // socket while the previous one does, we keep the previous close action.\n158:       return;\n159:     }\n160:   }\n161: \n162:   // Close the connection if we have no pending filters.\n163:   // The close is initialized by the connection and no filters are gating the close.\n164:   if (state_.filter_pending_close_count_ == 0) {\n165:     state_.local_close_pending_ = false;\n166:     state_.remote_close_pending_ = false;\n167:     connection_.closeConnection(close_action);\n168:     return;\n169:   }\n170: \n171:   latched_close_action_ = close_action;\n172:   state_.local_close_pending_ = close_action.isLocalClose();\n173:   state_.remote_close_pending_ = close_action.isRemoteClose();\n174: \n175:   // Otherwise, wait for filters to complete.\n176:   ENVOY_CONN_LOG(trace, \"delaying close: pending filters: {}\", connection_,\n177:                  state_.filter_pending_close_count_);\n178: }\n179: \n180: FilterStatus FilterManagerImpl::onWrite() { return onWrite(nullptr, connection_); }\n181: \n182: FilterStatus FilterManagerImpl::onWrite(ActiveWriteFilter* filter,\n183:                                         WriteBufferSource\u0026 buffer_source) {\n184: