41: bool FilterManagerImpl::initializeReadFilters() {
42:   if (upstream_filters_.empty()) {
43:     return false;
44:   }
45: 
46:   // Initialize read filters without calling onData() afterwards.
47:   // This is called just after an connection has been established and nothing may have been read
48:   // yet. onData() will be called separately as data is read from the connection.
49:   for (auto& entry : upstream_filters_) {
50:     if (entry->filter_ && !entry->initialized_) {
51:       entry->initialized_ = true;
52:       FilterStatus status = entry->filter_->onNewConnection();
53:       if (status == FilterStatus::StopIteration || connection_.state() != Connection::State::Open) {
54:         break;
55:       }
56:     }
57:   }
58: 
59:   return true;
60: }
