180: FilterStatus FilterManagerImpl::onWrite() { return onWrite(nullptr, connection_); }
181: 
182: FilterStatus FilterManagerImpl::onWrite(ActiveWriteFilter* filter,
183:                                         WriteBufferSource& buffer_source) {
184:   // Filter could return status == FilterStatus::StopIteration immediately, close the connection and
185:   // use callback to call this function.
186:   if (connection_.state() != Connection::State::Open) {
187:     return FilterStatus::StopIteration;
188:   }
189: 
190:   // Only inject write is allowed when the connection is pending local close.
191:   // Injected writes are associated with a filter object.
192:   // If the connection is pending close, regular writes are not permitted.
193:   if (filter ? state_.remote_close_pending_ : pendingClose()) {
194:     return FilterStatus::StopIteration;
195:   }
196: 
197:   std::list<ActiveWriteFilterPtr>::iterator entry;
198:   if (!filter) {
199:     entry = downstream_filters_.begin();
200:   } else {
201:     entry = std::next(filter->entry());
202:   }
203: 
204:   for (; entry != downstream_filters_.end(); entry++) {
205:     StreamBuffer write_buffer = buffer_source.getWriteBuffer();
206:     FilterStatus status = (*entry)->filter_->onWrite(write_buffer.buffer, write_buffer.end_stream);
207:     if (status == FilterStatus::StopIteration || connection_.state() != Connection::State::Open) {
208:       return FilterStatus::StopIteration;
209:     }
210:   }
211: 
212:   // Report the final bytes written to the wire
213:   connection_.streamInfo().addBytesSent(buffer_source.getWriteBuffer().buffer.length());
214:   return FilterStatus::Continue;
215: }
