217: void FilterManagerImpl::onResumeWriting(ActiveWriteFilter* filter,
218:                                         WriteBufferSource& buffer_source) {
219:   auto status = onWrite(filter, buffer_source);
220:   ENVOY_CONN_LOG(trace, "onResumeWriting: returned status={}", connection_,
221:                  static_cast<int>(status));
222:   if (status == FilterStatus::Continue) {
223:     StreamBuffer write_buffer = buffer_source.getWriteBuffer();
224:     connection_.rawWrite(write_buffer.buffer, write_buffer.end_stream);
225:   }
226: }
