143: void FilterUtility::setUpstreamScheme(Http::RequestHeaderMap& headers, bool downstream_ssl,
144:                                       bool upstream_ssl, bool use_upstream) {
145:   if (use_upstream) {
146:     if (upstream_ssl) {
147:       headers.setReferenceScheme(Http::Headers::get().SchemeValues.Https);
148:     } else {
149:       headers.setReferenceScheme(Http::Headers::get().SchemeValues.Http);
150:     }
151:     return;
152:   }
153: 
154:   if (Http::Utility::schemeIsValid(headers.getSchemeValue())) {
155:     return;
156:   }
157:   // After all the changes in https://github.com/envoyproxy/envoy/issues/14587
158:   // this path should only occur if a buggy filter has removed the :scheme
159:   // header. In that case best-effort set from X-Forwarded-Proto.
160:   absl::string_view xfp = headers.getForwardedProtoValue();
161:   if (Http::Utility::schemeIsValid(xfp)) {
162:     headers.setScheme(xfp);
163:     return;
164:   }
165: 
166:   if (downstream_ssl) {
167:     headers.setReferenceScheme(Http::Headers::get().SchemeValues.Https);
168:   } else {
169:     headers.setReferenceScheme(Http::Headers::get().SchemeValues.Http);
170:   }
