960: Http::FilterDataStatus Filter::decodeData(Buffer::Instance& data, bool end_stream) {
961:   // upstream_requests_.size() cannot be > 1 because that only happens when a per
962:   // try timeout occurs with hedge_on_per_try_timeout enabled but the per
963:   // try timeout timer is not started until onRequestComplete(). It could be zero
964:   // if the first request attempt has already failed and a retry is waiting for
965:   // a backoff timer.
966:   ASSERT(upstream_requests_.size() <= 1);
967: 
968:   bool buffering = (retry_state_ && retry_state_->enabled()) ||
969:                    (!active_shadow_policies_.empty() && !streaming_shadows_) ||
970:                    (route_entry_ && route_entry_->internalRedirectPolicy().enabled());
971:   if (buffering &&
972:       getLength(callbacks_->decodingBuffer()) + data.length() > retry_shadow_buffer_limit_) {
973:     ENVOY_LOG(debug,
974:               "The request payload has at least {} bytes data which exceeds buffer limit {}. Give "
975:               "up on the retry/shadow.",
976:               getLength(callbacks_->decodingBuffer()) + data.length(), retry_shadow_buffer_limit_);
977:     cluster_->trafficStats()->retry_or_shadow_abandoned_.inc();
978:     retry_state_.reset();
979:     buffering = false;
980:     active_shadow_policies_.clear();
981:     request_buffer_overflowed_ = true;
982: 
983:     // If we had to abandon buffering and there's no request in progress, abort the request and
984:     // clean up. This happens if the initial upstream request failed, and we are currently waiting
985:     // for a backoff timer before starting the next upstream attempt.
986:     if (upstream_requests_.empty()) {
987:       cleanup();
988:       callbacks_->sendLocalReply(
989:           Http::Code::InsufficientStorage, "exceeded request buffer limit while retrying upstream",
990:           modify_headers_, absl::nullopt,
991:           StreamInfo::ResponseCodeDetails::get().RequestPayloadExceededRetryBufferLimit);
992:       return Http::FilterDataStatus::StopIterationNoBuffer;
993:     }
994:   }
995: 
996:   for (auto* shadow_stream : shadow_streams_) {
997:     if (end_stream) {
998:       shadow_stream->removeDestructorCallback();
999:       shadow_stream->removeWatermarkCallbacks();
1000:     }
