73: bool ConnPoolImplBase::shouldConnect(size_t pending_streams, size_t active_streams,
74:                                      int64_t connecting_and_connected_capacity,
75:                                      float preconnect_ratio, bool anticipate_incoming_stream) {
76:   // This is set to true any time global preconnect is being calculated.
77:   // ClusterManagerImpl::maybePreconnect is called directly before a stream is created, so the
78:   // stream must be anticipated.
79:   //
80:   // Also without this, we would never pre-establish a connection as the first
81:   // connection in a pool because pending/active streams could both be 0.
82:   int anticipated_streams = anticipate_incoming_stream ? 1 : 0;
83: 
84:   // The number of streams we want to be provisioned for is the number of
85:   // pending, active, and anticipated streams times the preconnect ratio.
86:   // The number of streams we are (theoretically) provisioned for is the
87:   // connecting stream capacity plus the number of active streams.
88:   //
89:   // If preconnect ratio is not set, it defaults to 1, and this simplifies to the
90:   // legacy value of pending_streams_.size() > connecting_stream_capacity_
91:   return (pending_streams + active_streams + anticipated_streams) * preconnect_ratio >
92:          connecting_and_connected_capacity + active_streams;
93: }
